INSERT INTO `pronostico_anual` (`id`, `signo`, `year2022`, `year2023`, `year2024`, `year2025`) VALUES
(1, 'aries', 'Amor: Tendrás épocas difíciles y épocas felices para este año, habrán sucesos que te pondrán aprueba.\r\nDinero: Toma siempre las mejores decisiones para que tú dinero alcance, y estés tranquilo en este sentido.\r\nSalud: Cuida de tu salud, solo tu decidirás si continuas así o mejorarás\r\n', 'Amor: Tus vínculos con tu círculo social mejorarán.\r\nDinero: La prosperidad llegará llegará tarde que temprano, aunque no la percibas\r\nSalud: Tu salud se verá reflejada en lo que haces, si cuidas tu salud verás los resultados\r\n', 'Amor: Verás realmente quien te aprecia y quién no\r\nDinero: Llegarán tiempos difíciles pero los superarás de la mejor manera.\r\nSalud: Te sentirás mejor cuando solo hagas por ti\r\n', 'Amor: Los vinculos con tu gente cercana se reforzarán aún más, además vendrá alguien especial a tu camino\r\nDinero: Tu situación laboral mejorará\r\nSalud: Deberás cuidar de tu salud precisamente en tiempos de arduo trabajo\r\n'),
(2, 'tauro', 'Amor: Para este año verás quienes de verdad te aprecian y de verdad no\r\nDinero: Solo con tus acciones te definirá la prosperidad\r\nSalud: Tu condición de salud solo la definirlas tu con tus acciones\r\n', 'Amor: Encontrarás a las personas que de verdad te estiman\r\nDinero: El trabajo llegará, se constante\r\nSalud: La salud para este año solo la definirlas tú.\r\n', 'Amor: Llegarán personas a tu vida que te producirán situaciones emocionales fuertes, ten cuidado\r\nDinero: La prosperidad llegará si dejas de tomar malas decisiones\r\nSalud: La salud para este año estará estable\r\n', 'Amor: Superarás un afecto emocional, sin embargo, no recaigas en esta situación que te herirá aún más\r\nDinero: Debes salir de situaciones financieras graves, trata de no pedir tantos préstamos\r\nSalud: Tu salud se verá afectada por tu situación emocional, trata de estar en paz.\r\n');

