--
-- Estructura de tabla para la tabla `pronostico_mensual`
--

CREATE TABLE `pronostico_mensual` (
  `id` int(11) NOT NULL,
  `signo` varchar(20) NOT NULL,
  `enero` varchar(300) NOT NULL,
  `febrero` varchar(300) NOT NULL,
  `marzo` varchar(300) NOT NULL,
  `abril` varchar(300) NOT NULL,
  `mayo` varchar(300) NOT NULL,
  `junio` varchar(300) NOT NULL,
  `julio` varchar(300) NOT NULL,
  `agosto` varchar(300) NOT NULL,
  `septiembre` varchar(300) NOT NULL,
  `octubre` varchar(300) NOT NULL,
  `noviembre` varchar(300) NOT NULL,
  `diciembre` varchar(300) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Volcado de datos para la tabla `pronostico_mensual`
--

INSERT INTO `pronostico_mensual` (`id`, `signo`, `enero`, `febrero`, `marzo`, `abril`, `mayo`, `junio`, `julio`, `agosto`, `septiembre`, `octubre`, `noviembre`, `diciembre`) VALUES
(1, 'aries', 'Amor: El amor se probara con vinculos cercanos a ti. Ten cuidado con lo que haces.\nDinero: Habra algo de prosperidad en tu hogar\nSalud: Tu salud será benefica para este mes', 'Amor: Tu media naranja se encuentra cerca de ti, pero no te das cuenta, fijate en verdad a quien tienes al lado\r\nDinero: Vendrán tiempos dificiles para ti que te tomaran a prueba y debes superar\r\nSalud: Tu salud no resultara afectada este mes', 'Amor: Vendran sucesos dificiles que tienes que afrontar, se consciente en todo lo que haces, ya que puedes herir a alguien cercano a ti.\r\nDinero: Vendra prosperidad para ti\r\nSalud: Pues tener buena salud, sin embargo, ten cuidado con lo que comes', 'Amor: Se superaran todos los acontecimientos dificiles con tus vinculos cercanos, pero ten cuidado en esta etapa\nDinero: Debes ser más precavido con lo que gastas y consumes, ya que esto se vera reflejado en tu estado financiero\nSalud: Tu salud se mantendrá estable sin embargo, ten cuidado ', 'Amor: Tu estado emocional con tu circulo social mejorara, persevera en lo que buscas y quieres obtener\r\nDinero: Vendran dias prosperos y dias dificiles\r\nSalud: Tendras una salud buena si haces lo posible por cuidar de ella', 'Amor: El amor para este mes sera benefico, encontraras verdaderamente la persona que realmente te aprecia\r\nDinero: habra prosperidad para ti y tus allegados\r\nSalud: tu salud se mantendra estable', 'Amor: el amor se vera reflejado en ti, mejorara tu autestima\r\nDinero: Para este mes afrontaras tiempos dificiles, sin embargo, los superaras adecuadamente\r\nSalud: La salud estara un poco afectada, por lo que debes cuidar de ella', 'Amor: Afrontaras situaciones emocionales, trata de manejar de la mejor manera lo que dices y haces\r\nDinero: Tu situacion financiera se mantendra estable\r\nSalud: Tu salud se encontrara sana', 'Amor: El amor te pondra a prueba este mes\r\nDinero: Grandes oportunidades vendran a ti, que te beneficiaran economicamente\r\nSalud: Tu salud sera buena pero debes esforzarte en mejorarla', 'Amor: Para este mes veras las verdaderas personas que te aprecian y acompañan en las buenas y en las malas\r\nDinero: tu situacion financiera se vera un poco dificil, se perseverante en lo que buscas\r\nSalud: come bien este mes, veras los resultados', 'Amor: se presentaran algunos problemas con tu circulo social, trata de remediarlos de la mejor forma\r\nDinero: habra tiempos dificiles y tiempos abundantes\r\nSalud: Tu salud se vera un poco gastada, debes descansar', 'Amor: el amor se presentara mas en esta epoca de reunion y reconciliacion\r\nDinero: Vendran tiempos buenos y productivos\r\nSalud: Cuida de tu salud, mas que todo en lo que comes'),
(2, 'tauro', 'Amor: veras el amor reflejado en ti\r\nDinero: Tu situacion sera precaria\r\nSalud: tendras buena salud', 'Amor: Sin Amor\r\nDinero: Muy poco dinero\r\nSalud: convaleciente', 'Amor: encontraras una persona especial en ti\r\nDinero: La prosperidad llegara\r\nSalud: buena salud', 'Amor: Te llenaras de amor\r\nDinero: No te endeudes\r\nSalud: salud sana', 'Amor: No encontraras buenas personas\r\nDinero: Algo de dinero este mes\r\nSalud: Salud estable', 'Amor: Buen amor\r\nDinero: Necesitaras dinero\r\nSalud: ten cuidado con los accidentes', 'Amor: Tendras problemas familiares que afrontar\r\nDinero: Te pediran prestado tus allegados sin devolucion\r\nSalud: Perfecta salud', 'Amor: Mejor amor\r\nDinero: La abundancia llegara solo si tomas buenas decisiones\r\nSalud: Mejorara tu salud', 'Amor: Algo de amor\r\nDinero: Encontraras un buen trabajo\r\nSalud: Trata de comer sano y veras los resultados', 'Amor: Maravilloso amor\r\nDinero: La prosperidad vendra si tomas el camino correcto\r\nSalud: Algo de buena salud', 'Amor: Perfecto amor\r\nDinero: Te buscaran por interes\r\nSalud: Tu salud sera benefica', 'Amor: Reencontraras amores tanto familiares como propios perdidos\r\nDinero: Te endeudaras y pediras prestamos\r\nSalud: Evita comer comida no saludable');

